class HighImpactFixWorker(QtCore.QObject):
    progress = QtCore.Signal(int, int, int, int)
    finished = QtCore.Signal(object)
    failed = QtCore.Signal(str)

    def __init__(
        self,
        clashes: List[Clash],
        aabbs: Dict[str, tuple],
        config: HighImpactFixConfig,
    ):
        super().__init__()
        self._clashes = list(clashes)
        self._aabbs = dict(aabbs)
        self._config = config
        self._cancelled = False

    @QtCore.Slot()
    def run(self):
        try:
            result = findBestSingleMoveFixes(
                clashes=self._clashes,
                elementAabbs=self._aabbs,
                config=self._config,
                progressCallback=self._emit_progress,
                shouldCancel=self._should_cancel,
            )
            self.finished.emit(result)
        except Exception:
            self.failed.emit(traceback.format_exc())

    @QtCore.Slot()
    def cancel(self):
        self._cancelled = True

    def _should_cancel(self) -> bool:
        return bool(self._cancelled)

    def _emit_progress(
        self,
        element_idx: int,
        total_elements: int,
        trial_idx: int,
        total_trials: int,
    ) -> None:
        self.progress.emit(int(element_idx), int(total_elements), int(trial_idx), int(total_trials))


class DraggableClashCard(QtWidgets.QFrame):
    dragged = QtCore.Signal(float, float)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._drag_active = False
        self._resize_active = False
        self._drag_last_global: Optional[QtCore.QPointF] = None
        self._resize_origin_global: Optional[QtCore.QPointF] = None
        self._resize_origin_size: Optional[QtCore.QSize] = None
        self._resize_zone_px = 16
        self.setMinimumSize(320, 200)

    def _in_resize_zone(self, pos: QtCore.QPointF) -> bool:
        if pos is None:
            return False
        return bool(
            float(pos.x()) >= float(max(0, self.width() - self._resize_zone_px))
            and float(pos.y()) >= float(max(0, self.height() - self._resize_zone_px))
        )

    def mousePressEvent(self, event):
        if event.button() == QtCore.Qt.LeftButton:
            if self._in_resize_zone(event.position()):
                self._resize_active = True
                self._resize_origin_global = event.globalPosition()
                self._resize_origin_size = self.size()
                self.setCursor(QtCore.Qt.SizeFDiagCursor)
                event.accept()
                return
            self._drag_active = True
            self._drag_last_global = event.globalPosition()
            event.accept()
            return
        super().mousePressEvent(event)

    def mouseMoveEvent(self, event):
        if self._resize_active and self._resize_origin_global is not None and self._resize_origin_size is not None:
            delta = event.globalPosition() - self._resize_origin_global
            new_w = max(self.minimumWidth(), int(self._resize_origin_size.width() + delta.x()))
            new_h = max(self.minimumHeight(), int(self._resize_origin_size.height() + delta.y()))
            self.resize(new_w, new_h)
            self.setCursor(QtCore.Qt.SizeFDiagCursor)
            event.accept()
            return
        if self._drag_active and self._drag_last_global is not None:
            now = event.globalPosition()
            dx = float(now.x() - self._drag_last_global.x())
            dy = float(now.y() - self._drag_last_global.y())
            self._drag_last_global = now
            if abs(dx) > 0.0 or abs(dy) > 0.0:
                self.dragged.emit(dx, dy)
            event.accept()
            return
        self.setCursor(QtCore.Qt.SizeFDiagCursor if self._in_resize_zone(event.position()) else QtCore.Qt.ArrowCursor)
        super().mouseMoveEvent(event)

    def mouseReleaseEvent(self, event):
        if event.button() == QtCore.Qt.LeftButton:
            if self._resize_active:
                self._resize_active = False
                self._resize_origin_global = None
                self._resize_origin_size = None
                self.setCursor(QtCore.Qt.ArrowCursor)
                event.accept()
                return
            self._drag_active = False
            self._drag_last_global = None
            event.accept()
            return
        super().mouseReleaseEvent(event)

    def leaveEvent(self, event):
        if not self._resize_active:
            self.setCursor(QtCore.Qt.ArrowCursor)
        super().leaveEvent(event)


class PropertiesSearchHighlightDelegate(QtWidgets.QStyledItemDelegate):
    def __init__(self, parent: Optional[QtCore.QObject] = None):
        super().__init__(parent)
        self._terms: List[str] = []

    def set_search_text(self, text: str) -> None:
        self._terms = [token.strip().lower() for token in str(text or "").split() if token.strip()]

    @staticmethod
    def _merge_ranges(text_lower: str, terms: List[str]) -> List[tuple[int, int]]:
        ranges: List[tuple[int, int]] = []
        for term in terms:
            start = 0
            while True:
                idx = text_lower.find(term, start)
                if idx < 0:
                    break
                ranges.append((idx, idx + len(term)))
                start = idx + len(term)
        if not ranges:
            return []
        ranges.sort(key=lambda pair: pair[0])
        merged: List[tuple[int, int]] = [ranges[0]]
        for left, right in ranges[1:]:
            prev_left, prev_right = merged[-1]
            if left <= prev_right:
                merged[-1] = (prev_left, max(prev_right, right))
            else:
                merged.append((left, right))
        return merged

    def paint(
        self,
        painter: QPainter,
        option: QtWidgets.QStyleOptionViewItem,
        index: QtCore.QModelIndex,
    ) -> None:
        if not self._terms:
            super().paint(painter, option, index)
            return
        opt = QtWidgets.QStyleOptionViewItem(option)
        self.initStyleOption(opt, index)
        full_text = str(opt.text or "")
        if not full_text:
            super().paint(painter, option, index)
            return

        style = opt.widget.style() if opt.widget is not None else QtWidgets.QApplication.style()
        opt.text = ""
        style.drawControl(QtWidgets.QStyle.CE_ItemViewItem, opt, painter, opt.widget)
        text_rect = style.subElementRect(QtWidgets.QStyle.SE_ItemViewItemText, opt, opt.widget).adjusted(2, 0, -2, 0)
        if text_rect.width() <= 2:
            return
        display_text = opt.fontMetrics.elidedText(full_text, opt.textElideMode, text_rect.width())
        if not display_text:
            return

        painter.save()
        intervals = self._merge_ranges(display_text.lower(), self._terms)
        highlight = QColor(255, 59, 154, 84)
        if opt.state & QtWidgets.QStyle.State_Selected:
            highlight = QColor(255, 255, 255, 88)
        for start, end in intervals:
            if end <= start:
                continue
            left = text_rect.x() + opt.fontMetrics.horizontalAdvance(display_text[:start])
            width = opt.fontMetrics.horizontalAdvance(display_text[start:end])
            if width <= 0:
                continue
            rect = QtCore.QRect(left, text_rect.y() + 2, width, max(2, text_rect.height() - 4))
            painter.fillRect(rect, highlight)
        role = QtGui.QPalette.HighlightedText if (opt.state & QtWidgets.QStyle.State_Selected) else QtGui.QPalette.Text
        painter.setPen(opt.palette.color(role))
        painter.drawText(text_rect, int(QtCore.Qt.AlignVCenter | QtCore.Qt.AlignLeft), display_text)
        painter.restore()


class CollapsibleSection(QtWidgets.QFrame):
    def __init__(self, title: str, *, collapsed: bool = False, parent: Optional[QtWidgets.QWidget] = None):
        super().__init__(parent)
        self.setObjectName("CollapsibleSection")
        self.setAttribute(QtCore.Qt.WA_StyledBackground, True)
        self.setContentsMargins(0, 0, 0, 0)
        self.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Maximum)
        self.setMinimumHeight(0)
        self._header_min_height = 30
        self._header_max_height = 30
        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(0)

        self.header_btn = QtWidgets.QToolButton(self)
        self.header_btn.setText(str(title or "Section"))
        self.header_btn.setCheckable(True)
        self.header_btn.setChecked(not bool(collapsed))
        self.header_btn.setProperty("noRowToggle", True)
        self.header_btn.setProperty("data-no-row-toggle", True)
        self.header_btn.setToolButtonStyle(QtCore.Qt.ToolButtonTextBesideIcon)
        self.header_btn.setIconSize(QtCore.QSize(10, 10))
        self.header_btn.setMinimumHeight(self._header_min_height)
        self.header_btn.setMaximumHeight(self._header_max_height)
        self.header_btn.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed)
        self.header_btn.setArrowType(QtCore.Qt.DownArrow if self.header_btn.isChecked() else QtCore.Qt.RightArrow)
        self.header_btn.toggled.connect(self._on_toggled)
        layout.addWidget(self.header_btn, 0)

        self.content = QtWidgets.QWidget(self)
        self.content.setObjectName("CollapsibleSectionContent")
        self.content.setAutoFillBackground(True)
        self.content.setAttribute(QtCore.Qt.WA_OpaquePaintEvent, True)
        self.content.setAttribute(QtCore.Qt.WA_DontShowOnScreen, not self.header_btn.isChecked())
        self.content.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed)
        content_policy = self.content.sizePolicy()
        content_policy.setRetainSizeWhenHidden(False)
        self.content.setSizePolicy(content_policy)
        self.content.setMinimumHeight(0)
        self.content_layout = QtWidgets.QVBoxLayout(self.content)
        self.content_layout.setContentsMargins(0, 0, 0, 0)
        self.content_layout.setSpacing(0)
        self.content.setVisible(self.header_btn.isChecked())
        self.content.setMaximumHeight(16777215 if self.header_btn.isChecked() else 0)
        layout.addWidget(self.content, 0)
        self._content_anim = QtCore.QPropertyAnimation(self.content, b"maximumHeight", self)
        self._content_anim.setDuration(150)
        self._content_anim.setEasingCurve(QtCore.QEasingCurve.OutCubic)
        self._content_anim.finished.connect(self._on_animation_finished)

        self.setStyleSheet(
            normalize_stylesheet(
                f"""
                QFrame#CollapsibleSection {{
                    background: {theme_rgba(DARK_THEME.colors.background_deep, 1.00)};
                    border: none;
                    margin: 0px;
                    padding: 0px;
                    min-height: 0px;
                }}
                QFrame#CollapsibleSection QToolButton {{
                    border-top: none;
                    border-bottom: 1px solid {theme_rgba(DARK_THEME.colors.text_primary, 0.11)};
                    border-left: 1px solid {theme_rgba(DARK_THEME.colors.text_primary, 0.10)};
                    border-right: 1px solid {theme_rgba(DARK_THEME.colors.text_primary, 0.10)};
                    background: {theme_rgba(DARK_THEME.colors.background_deep, 1.00)};
                    color: {theme_rgba(DARK_THEME.colors.text_secondary, 0.84)};
                    font-size: 14px;
                    font-weight: 500;
                    padding: 0px 10px 0px 8px;
                    margin: 0px;
                    min-height: 30px;
                    max-height: 30px;
                    text-align: left;
                }}
                QFrame#CollapsibleSection QToolButton:checked {{
                    color: {theme_rgba(DARK_THEME.colors.text_secondary, 0.9)};
                    background: {theme_rgba(DARK_THEME.colors.background_deep, 1.00)};
                }}
                QFrame#CollapsibleSection QToolButton:hover {{
                    color: {DARK_THEME.colors.text_primary};
                    background: {theme_rgba(DARK_THEME.colors.panel, 1.00)};
                }}
                QFrame#CollapsibleSection QToolButton[inspectDebugOutline="true"] {{
                    border: 1px solid rgba(255, 76, 76, 0.95);
                }}
                QWidget#CollapsibleSectionContent {{
                    margin: 0px;
                    padding: 0px;
                    border: none;
                    min-height: 0px;
                }}
                """,
                DARK_THEME,
            )
        )

    def _apply_content_visibility(self, expanded: bool) -> None:
        if expanded:
            self.content.setAttribute(QtCore.Qt.WA_DontShowOnScreen, False)
            self.content.setVisible(True)
            self.content.setMinimumHeight(0)
            self.content.setMaximumHeight(16777215)
            self.content.updateGeometry()
            self.updateGeometry()
            return
        self.content.setAttribute(QtCore.Qt.WA_DontShowOnScreen, True)
        self.content.setMinimumHeight(0)
        self.content.setMaximumHeight(0)
        self.content.resize(max(0, int(self.content.width())), 0)
        self.content.setVisible(False)
        self.content.updateGeometry()
        self.updateGeometry()

    def _on_toggled(self, checked: bool) -> None:
        expanded = bool(checked)
        self.header_btn.setArrowType(QtCore.Qt.DownArrow if expanded else QtCore.Qt.RightArrow)
        self._content_anim.stop()
        if int(self._content_anim.duration()) <= 0:
            self._apply_content_visibility(expanded)
            return
        if expanded:
            target = max(1, int(self.content.sizeHint().height()))
            self.content.setVisible(True)
            start = max(0, int(self.content.maximumHeight()))
            if start <= 0:
                start = 0
            self._content_anim.setStartValue(start)
            self._content_anim.setEndValue(target)
            self._content_anim.start()
            return
        start = max(0, int(self.content.height() or self.content.maximumHeight()))
        if start <= 0:
            start = max(1, int(self.content.sizeHint().height()))
        self._content_anim.setStartValue(start)
        self._content_anim.setEndValue(0)
        self._content_anim.start()

    def _on_animation_finished(self) -> None:
        self._apply_content_visibility(bool(self.header_btn.isChecked()))

    def set_collapsed(self, collapsed: bool) -> None:
        self.header_btn.setChecked(not bool(collapsed))

    def is_collapsed(self) -> bool:
        return not bool(self.header_btn.isChecked())


class PropertySection(CollapsibleSection):
    toggled = QtCore.Signal(bool)

    def __init__(self, title: str, *, defaultOpen: bool = True, parent: Optional[QtWidgets.QWidget] = None):
        super().__init__(title, collapsed=(not bool(defaultOpen)), parent=parent)
        self.header_btn.toggled.connect(lambda checked: self.toggled.emit(bool(checked)))


class PropertyRow(QtWidgets.QFrame):
    favoriteRequested = QtCore.Signal(str, str)
    copyRequested = QtCore.Signal(str)
    detailsToggled = QtCore.Signal(bool)
    selectionClicked = QtCore.Signal(object, bool, bool)
    navigateRequested = QtCore.Signal(object, int)
    CHECKBOX_COLUMN_WIDTH = 36
    PROPERTY_COLUMN_MIN_WIDTH = 180
    VALUE_COLUMN_MIN_WIDTH = 220
    ROW_LEFT_MARGIN = 8
    ROW_LEFT_MARGIN_SUBROW = 24
    ROW_RIGHT_MARGIN = 12
    ACTIONS_COLUMN_WIDTH = 72

    def __init__(
        self,
        *,
        label: str,
        value: str,
        source_group: str = "",
        source_key: str = "",
        favorite: bool = False,
        detail_rows: Optional[Sequence[tuple[str, str, str, str]]] = None,
        details_expanded: bool = False,
        subrow: bool = False,
        selection_key: str = "",
        selected: bool = False,
        selectable: bool = True,
        right_icon: Optional[QIcon] = None,
        onCopy: Optional[Callable[[], None]] = None,
        onFavorite: Optional[Callable[[], None]] = None,
        parent: Optional[QtWidgets.QWidget] = None,
    ) -> None:
        super().__init__(parent)
        self.setProperty("inspectRow", True)
        self.setProperty("inspectSubRow", bool(subrow))
        self.setProperty("selected", bool(selected and selectable and selection_key))
        self.setProperty("role", "row")
        self.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed)
        self.setFocusPolicy(QtCore.Qt.StrongFocus if not bool(subrow) else QtCore.Qt.NoFocus)
        self.setMinimumHeight(34)
        self.setMaximumHeight(36)
        self._subrow = bool(subrow)
        self._source_group = str(source_group or "")
        self._source_key = str(source_key or "")
        self._selection_key = str(selection_key or "")
        self._selectable = bool(selectable and self._selection_key)
        self._selected = bool(selected and self._selectable)
        self._label_text = str(label or "").strip()
        self._label_base_text = str(self._label_text)
        self._full_value = str(value or "-").strip() or "-"
        self._expanded = False
        self._detail_rows = list(detail_rows or [])
        self._details_expanded = bool(details_expanded and self._detail_rows)
        self._favorite = bool(favorite)
        self._hovered = False
        self._focused = False
        self._on_copy = onCopy
        self._on_favorite = onFavorite
        self._copyable = self._is_copyable_value(
            source_group=self._source_group,
            source_key=self._source_key,
            label=self._label_text,
            value=self._full_value,
        )
        self._numeric_value = self._looks_numeric(self._full_value)

        layout = QtWidgets.QGridLayout(self)
        layout.setContentsMargins(
            self.ROW_LEFT_MARGIN if not self._subrow else self.ROW_LEFT_MARGIN_SUBROW,
            1,
            self.ROW_RIGHT_MARGIN,
            1,
        )
        layout.setHorizontalSpacing(5)
        layout.setVerticalSpacing(0)
        layout.setColumnMinimumWidth(0, self.CHECKBOX_COLUMN_WIDTH)
        layout.setColumnMinimumWidth(1, self.PROPERTY_COLUMN_MIN_WIDTH)
        layout.setColumnMinimumWidth(2, self.VALUE_COLUMN_MIN_WIDTH)
        self.select_cb = QtWidgets.QCheckBox(self)
        self.select_cb.setObjectName("InspectPropertySelect")
        self.select_cb.setProperty("noRowToggle", True)
        self.select_cb.setProperty("data-no-row-toggle", True)
        self.select_cb.setTristate(False)
        self.select_cb.setFocusPolicy(QtCore.Qt.NoFocus)
        self.select_cb.setChecked(bool(self._selected))
        self.select_cb.setVisible(bool(self._selectable))
        self.select_cb.toggled.connect(self._on_checkbox_toggled)
        layout.addWidget(self.select_cb, 0, 0, 1, 1, QtCore.Qt.AlignVCenter | QtCore.Qt.AlignHCenter)
        self.label_w = QtWidgets.QLabel(str(self._label_text), self)
        self.label_w.setProperty("inspectLabel", True)
        self.label_w.setProperty("inspectPropertyCell", True)
        if self._subrow:
            self.label_w.setProperty("inspectDetailLabel", True)
        self.label_w.setMinimumWidth(self.PROPERTY_COLUMN_MIN_WIDTH)
        self.label_w.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Preferred)
        self.value_w = QtWidgets.QLabel(self._full_value, self)
        self.value_w.setProperty("inspectValue", True)
        if self._subrow:
            self.value_w.setProperty("inspectDetailValue", True)
        self.value_w.setTextInteractionFlags(QtCore.Qt.TextSelectableByMouse)
        self.value_w.setWordWrap(False)
        self.value_w.setAlignment(
            QtCore.Qt.AlignVCenter | (QtCore.Qt.AlignRight if self._numeric_value else QtCore.Qt.AlignLeft)
        )
        self.value_w.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Preferred)
        layout.addWidget(self.label_w, 0, 1, 1, 1, QtCore.Qt.AlignVCenter | QtCore.Qt.AlignLeft)

        self.actions_wrap = QtWidgets.QWidget(self)
        self.actions_wrap.setProperty("inspectActionCell", True)
        actions_layout = QtWidgets.QHBoxLayout(self.actions_wrap)
        actions_layout.setContentsMargins(6, 0, 10, 0)
        actions_layout.setSpacing(8)
        self.actions_wrap.setFixedWidth(self.ACTIONS_COLUMN_WIDTH)
        self.actions_wrap.setSizePolicy(QtWidgets.QSizePolicy.Fixed, QtWidgets.QSizePolicy.Fixed)
        actions_layout.addStretch(1)

        self.copy_btn = QtWidgets.QToolButton(self.actions_wrap)
        self.copy_btn.setProperty("inspectCopyButton", True)
        self.copy_btn.setProperty("inspectCopyVisible", False)
        self.copy_btn.setProperty("noRowToggle", True)
        self.copy_btn.setProperty("data-no-row-toggle", True)
        self.copy_btn.setAutoRaise(True)
        self.copy_btn.setToolTip("Copy value")
        self.copy_btn.setText("")
        self.copy_btn.setIconSize(QtCore.QSize(12, 12))
        if right_icon is None:
            right_icon = QtGui.QIcon.fromTheme("edit-copy")
        if right_icon is None or right_icon.isNull():
            right_icon = self.style().standardIcon(QtWidgets.QStyle.SP_DialogResetButton)
        self.copy_btn.setIcon(right_icon)
        self.copy_btn.setEnabled(False)
        self.copy_btn.setVisible(False)
        self.copy_btn.clicked.connect(self._emit_copy)
        actions_layout.addWidget(self.copy_btn, 0, QtCore.Qt.AlignVCenter)

        self.favorite_btn = QtWidgets.QToolButton(self.actions_wrap)
        self.favorite_btn.setProperty("inspectFavButton", True)
        self.favorite_btn.setProperty("noRowToggle", True)
        self.favorite_btn.setProperty("data-no-row-toggle", True)
        self.favorite_btn.setCursor(QtCore.Qt.PointingHandCursor)
        self.favorite_btn.setAutoRaise(True)
        self.favorite_btn.setText("♥" if bool(self._favorite) else "♡")
        self.favorite_btn.setProperty("favorite", bool(self._favorite))
        self.favorite_btn.setProperty("hovered", False)
        self.favorite_btn.setProperty("visibleState", bool(self._favorite))
        self.favorite_btn.setEnabled(bool(self._source_group and self._source_key and self._favorite))
        self.favorite_btn.setToolTip("Toggle favorite")
        self.favorite_btn.clicked.connect(self._emit_favorite)
        actions_layout.addWidget(self.favorite_btn, 0, QtCore.Qt.AlignVCenter)

        self.value_cell = QtWidgets.QWidget(self)
        self.value_cell.setProperty("inspectValueCell", True)
        value_cell_layout = QtWidgets.QHBoxLayout(self.value_cell)
        value_cell_layout.setContentsMargins(8, 0, 8, 0)
        value_cell_layout.setSpacing(0)
        value_cell_layout.addWidget(self.value_w, 1)
        layout.addWidget(self.value_cell, 0, 2, 1, 1)
        layout.addWidget(self.actions_wrap, 0, 3, 1, 1, QtCore.Qt.AlignVCenter | QtCore.Qt.AlignRight)
        layout.setColumnStretch(1, 0)
        layout.setColumnStretch(2, 0)
        layout.setColumnMinimumWidth(3, self.ACTIONS_COLUMN_WIDTH)
        self._update_detail_header()
        self._update_value_label()
        for row_surface in (self.label_w, self.value_cell, self.value_w, self.actions_wrap):
            row_surface.installEventFilter(self)
        self._update_selected_visual_state()
        self._sync_action_visibility()

    @staticmethod
    def _looks_numeric(value: str) -> bool:
        text = str(value or "").strip()
        if not text:
            return False
        normalized = " ".join(text.replace("\n", " ").split())
        normalized = re.sub(r"^[<>=~≈\s]+", "", normalized).strip()
        if not normalized:
            return False
        unit_re = (
            r"(?:%|‰|mm|cm|m|km|in|ft|yd|deg|°|rad|pa|kpa|mpa|bar|n|kn|kg|g|lb|lbs|m2|m3|sqm|sqft)"
        )
        number_re = r"[+-]?\d{1,3}(?:[ ,]\d{3})*(?:[.,]\d+)?|[+-]?\d+(?:[.,]\d+)?"
        full_re = rf"^(?:{number_re})(?:\s*{unit_re})?$"
        if re.match(full_re, normalized, flags=re.IGNORECASE):
            return True
        compact_re = rf"^[+-]?\d+(?:[.,]\d+)?(?:{unit_re})$"
        return bool(re.match(compact_re, normalized, flags=re.IGNORECASE))

    @staticmethod
    def _normalize_key_text(value: str) -> str:
        return "".join(ch for ch in str(value or "").lower() if ch.isalnum())

    @classmethod
    def _is_copyable_value(cls, *, source_group: str, source_key: str, label: str, value: str) -> bool:
        raw_value = str(value or "").strip()
        if not raw_value or raw_value == "-":
            return False
        group_norm = str(source_group or "").strip().lower()
        if group_norm.startswith("inspect:rule") or group_norm.startswith("inspect:search_set_debug"):
            return False
        return True

    @staticmethod
    def _collapsed_value_text(
        value: str,
        *,
        max_chars: int = 96,
        metrics: Optional[QtGui.QFontMetrics] = None,
        max_width: int = 0,
    ) -> str:
        raw = str(value or "")
        single_line = " ".join(raw.replace("\r", " ").replace("\n", " ").split())
        if metrics is not None and int(max_width) > 0:
            return str(metrics.elidedText(single_line, QtCore.Qt.ElideRight, int(max_width)))
        if len(single_line) <= int(max_chars):
            return single_line
        trimmed = single_line[: max(1, int(max_chars) - 1)].rstrip()
        return f"{trimmed}…"

    @classmethod
    def _is_expandable_value(cls, value: str, collapsed: str) -> bool:
        raw = str(value or "")
        if "\n" in raw or "\r" in raw:
            return True
        return str(collapsed or "") != str(raw or "")

    def _update_value_label(self) -> None:
        available_width = max(64, int(self.value_w.width()) - 4)
        collapsed = self._collapsed_value_text(
            self._full_value,
            metrics=self.value_w.fontMetrics(),
            max_width=available_width,
        )
        expandable = self._is_expandable_value(self._full_value, collapsed)
        if self._expanded and expandable:
            self.value_w.setText(self._full_value)
            self.value_w.setWordWrap(True)
            self.value_w.setAlignment(
                QtCore.Qt.AlignTop | (QtCore.Qt.AlignRight if self._numeric_value else QtCore.Qt.AlignLeft)
            )
            self.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Preferred)
            self.setMaximumHeight(220)
        else:
            self.value_w.setText(collapsed)
            self.value_w.setWordWrap(False)
            self.value_w.setAlignment(
                QtCore.Qt.AlignVCenter | (QtCore.Qt.AlignRight if self._numeric_value else QtCore.Qt.AlignLeft)
            )
            self.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed)
            self.setMaximumHeight(36)
        self.value_w.setToolTip(self._full_value if expandable else "")
        cursor = QtCore.Qt.ArrowCursor
        if self.is_selectable():
            cursor = QtCore.Qt.PointingHandCursor
        elif expandable or self.has_detail_rows():
            cursor = QtCore.Qt.PointingHandCursor
        self.setCursor(cursor)
        for row_surface in (self.label_w, self.value_cell, self.value_w, self.actions_wrap):
            row_surface.setCursor(cursor)

    def _update_detail_header(self) -> None:
        if self.has_detail_rows():
            chevron = "▾" if self._details_expanded else "▸"
            self.label_w.setText(f"{chevron} {self._label_base_text}")
            self.label_w.setToolTip("Click to expand details")
            return
        self.label_w.setText(self._label_base_text)
        self.label_w.setToolTip("")

    def has_detail_rows(self) -> bool:
        return bool(self._detail_rows)

    def selection_key(self) -> str:
        return str(self._selection_key or "")

    def is_selected(self) -> bool:
        return bool(self._selected)

    def is_selectable(self) -> bool:
        return bool(self._selectable)

    def _update_selected_visual_state(self) -> None:
        self.setProperty("selected", bool(self._selected and self._selectable))
        style = self.style()
        if style is not None:
            style.unpolish(self)
            style.polish(self)
        self.update()

    def set_selected(self, selected: bool) -> bool:
        if not self._selectable:
            changed = bool(self._selected)
            self._selected = False
            self._update_selected_visual_state()
            return bool(changed)
        next_state = bool(selected)
        changed = next_state != bool(self._selected)
        self._selected = next_state
        blocker = QtCore.QSignalBlocker(self.select_cb)
        self.select_cb.setChecked(bool(self._selected))
        del blocker
        self._update_selected_visual_state()
        return changed

    def _on_checkbox_toggled(self, checked: bool) -> None:
        if not self._selectable:
            return
        self._selected = bool(checked)
        self._update_selected_visual_state()
        modifiers = QtWidgets.QApplication.keyboardModifiers()
        shift_pressed = bool(modifiers & QtCore.Qt.ShiftModifier)
        self.selectionClicked.emit(self, bool(checked), shift_pressed)

    def detail_rows(self) -> List[tuple[str, str, str, str]]:
        return list(self._detail_rows)

    def is_details_expanded(self) -> bool:
        return bool(self._details_expanded)

    def set_details_expanded(self, expanded: bool) -> None:
        if not self.has_detail_rows():
            self._details_expanded = False
            return
        next_state = bool(expanded)
        if self._details_expanded == next_state:
            return
        self._details_expanded = next_state
        self._update_detail_header()
        self.detailsToggled.emit(bool(self._details_expanded))

    def _emit_copy(self) -> None:
        text = str(self._full_value or "").strip()
        if not text or text == "-":
            return
        self.copyRequested.emit(text)
        if callable(self._on_copy):
            self._on_copy()

    def _emit_favorite(self) -> None:
        if not self._source_group or not self._source_key:
            return
        self.favoriteRequested.emit(str(self._source_group), str(self._source_key))
        if callable(self._on_favorite):
            self._on_favorite()

    def _can_toggle_favorite(self) -> bool:
        return bool((not self._subrow) and self._source_group and self._source_key)

    def _sync_action_visibility(self) -> None:
        can_favorite = self._can_toggle_favorite()
        favorite_visible = bool(can_favorite)
        self.favorite_btn.setProperty("hovered", bool(self._hovered))
        self.favorite_btn.setProperty("visibleState", bool(favorite_visible))
        self.favorite_btn.setEnabled(bool(can_favorite))
        self.favorite_btn.setVisible(bool(favorite_visible))
        show_copy = bool(self._copyable)
        self.copy_btn.setProperty("inspectCopyVisible", show_copy)
        self.copy_btn.setEnabled(show_copy)
        self.copy_btn.setVisible(show_copy)
        for button in (self.copy_btn, self.favorite_btn):
            style = button.style()
            if style is not None:
                style.unpolish(button)
                style.polish(button)
            button.update()

    def set_hovered(self, hovered: bool) -> None:
        self._hovered = bool(hovered)
        self._sync_action_visibility()

    def focusInEvent(self, event: QtGui.QFocusEvent) -> None:
        self._focused = True
        self._sync_action_visibility()
        super().focusInEvent(event)

    def focusOutEvent(self, event: QtGui.QFocusEvent) -> None:
        self._focused = False
        self._sync_action_visibility()
        super().focusOutEvent(event)

    def _is_no_row_toggle_widget(self, widget: Optional[QtWidgets.QWidget]) -> bool:
        if widget is None:
            return False
        candidate = widget
        while isinstance(candidate, QtWidgets.QWidget):
            if candidate is self:
                break
            if bool(candidate.property("noRowToggle")) or bool(candidate.property("data-no-row-toggle")):
                return True
            if isinstance(
                candidate,
                (
                    QtWidgets.QAbstractButton,
                    QtWidgets.QLineEdit,
                    QtWidgets.QComboBox,
                    QtWidgets.QAbstractSpinBox,
                    QtWidgets.QTextEdit,
                    QtWidgets.QPlainTextEdit,
                    QtWidgets.QAbstractItemView,
                ),
            ):
                return True
            if isinstance(candidate, QtWidgets.QLabel):
                flags = candidate.textInteractionFlags()
                if bool(flags & QtCore.Qt.LinksAccessibleByMouse) or bool(candidate.openExternalLinks()):
                    return True
            candidate = candidate.parentWidget()
        return False

    def _toggle_row_selection_from_input(self, *, shift_pressed: bool) -> None:
        if not self.is_selectable():
            return
        next_state = not bool(self._selected)
        self.set_selected(next_state)
        self.selectionClicked.emit(self, bool(next_state), bool(shift_pressed))

    def _handle_row_primary_click(
        self,
        *,
        row_pos: QtCore.QPoint,
        modifiers: QtCore.Qt.KeyboardModifiers,
    ) -> bool:
        if self._is_detail_caret_hit(row_pos):
            self.set_details_expanded(not self._details_expanded)
            return True
        if not self.is_selectable():
            return False
        shift_pressed = bool(modifiers & QtCore.Qt.ShiftModifier)
        self._toggle_row_selection_from_input(shift_pressed=shift_pressed)
        return True

    def _handle_row_double_click(self, *, row_pos: QtCore.QPoint) -> bool:
        if self.has_detail_rows():
            if self._is_detail_caret_hit(row_pos):
                return False
            self.set_details_expanded(not self._details_expanded)
            return True
        collapsed = self._collapsed_value_text(
            self._full_value,
            metrics=self.value_w.fontMetrics(),
            max_width=max(64, int(self.value_w.width()) - 4),
        )
        if self._is_expandable_value(self._full_value, collapsed):
            self._expanded = not bool(self._expanded)
            self._update_value_label()
            return True
        return False

    def _is_detail_caret_hit(self, row_pos: QtCore.QPoint) -> bool:
        if not self.has_detail_rows():
            return False
        if not isinstance(row_pos, QtCore.QPoint):
            return False
        label_pos = self.label_w.mapFrom(self, row_pos)
        if not self.label_w.rect().contains(label_pos):
            return False
        caret_text = "▾ " if self._details_expanded else "▸ "
        caret_width = max(12, int(self.label_w.fontMetrics().horizontalAdvance(caret_text)) + 4)
        return int(label_pos.x()) <= caret_width

    def mousePressEvent(self, event: QtGui.QMouseEvent) -> None:
        if event.button() == QtCore.Qt.LeftButton:
            if self.focusPolicy() != QtCore.Qt.NoFocus:
                self.setFocus(QtCore.Qt.MouseFocusReason)
            pos = event.position().toPoint()
            target = self.childAt(pos)
            if self._is_no_row_toggle_widget(target):
                super().mousePressEvent(event)
                return
            if self._handle_row_primary_click(row_pos=pos, modifiers=event.modifiers()):
                event.accept()
                return
        super().mousePressEvent(event)

    def mouseDoubleClickEvent(self, event: QtGui.QMouseEvent) -> None:
        if event.button() == QtCore.Qt.LeftButton:
            pos = event.position().toPoint()
            target = self.childAt(pos)
            if self._is_no_row_toggle_widget(target):
                super().mouseDoubleClickEvent(event)
                return
            if self._handle_row_double_click(row_pos=pos):
                event.accept()
                return
        super().mouseDoubleClickEvent(event)

    def eventFilter(self, watched: QtCore.QObject, event: QtCore.QEvent) -> bool:
        if watched in (self.label_w, self.value_cell, self.value_w, self.actions_wrap):
            event_type = int(event.type())
            if event_type == int(QtCore.QEvent.MouseButtonPress) and isinstance(event, QtGui.QMouseEvent):
                if event.button() == QtCore.Qt.LeftButton:
                    if self.focusPolicy() != QtCore.Qt.NoFocus:
                        self.setFocus(QtCore.Qt.MouseFocusReason)
                    if isinstance(watched, QtWidgets.QWidget) and self._is_no_row_toggle_widget(watched):
                        return False
                    row_pos = watched.mapTo(self, event.position().toPoint()) if isinstance(watched, QtWidgets.QWidget) else event.position().toPoint()
                    if self._handle_row_primary_click(row_pos=row_pos, modifiers=event.modifiers()):
                        event.accept()
                        return True
            if event_type == int(QtCore.QEvent.MouseButtonDblClick) and isinstance(event, QtGui.QMouseEvent):
                if event.button() == QtCore.Qt.LeftButton:
                    if isinstance(watched, QtWidgets.QWidget) and self._is_no_row_toggle_widget(watched):
                        return False
                    row_pos = watched.mapTo(self, event.position().toPoint()) if isinstance(watched, QtWidgets.QWidget) else event.position().toPoint()
                    if self._handle_row_double_click(row_pos=row_pos):
                        event.accept()
                        return True
        return super().eventFilter(watched, event)

    def contextMenuEvent(self, event: QtGui.QContextMenuEvent) -> None:
        if not self._can_toggle_favorite():
            super().contextMenuEvent(event)
            return
        menu = QtWidgets.QMenu(self)
        action_text = "Remove favorite" if bool(self._favorite) else "Add to favorites"
        action = menu.addAction(action_text)
        action.triggered.connect(self._emit_favorite)
        menu.exec(event.globalPos())
        event.accept()

    def keyPressEvent(self, event: QtGui.QKeyEvent) -> None:
        if event.key() in (QtCore.Qt.Key_Up, QtCore.Qt.Key_Down):
            delta = -1 if event.key() == QtCore.Qt.Key_Up else 1
            self.navigateRequested.emit(self, int(delta))
            event.accept()
            return
        if self.is_selectable() and event.key() in (QtCore.Qt.Key_Space, QtCore.Qt.Key_Return, QtCore.Qt.Key_Enter):
            modifiers = QtWidgets.QApplication.keyboardModifiers()
            shift_pressed = bool(modifiers & QtCore.Qt.ShiftModifier)
            self._toggle_row_selection_from_input(shift_pressed=shift_pressed)
            event.accept()
            return
        if self._can_toggle_favorite() and event.key() == QtCore.Qt.Key_F:
            self._emit_favorite()
            event.accept()
            return
        super().keyPressEvent(event)

    def resizeEvent(self, event: QtGui.QResizeEvent) -> None:
        super().resizeEvent(event)
        self._update_value_label()


class InspectPropertyGrid(QtWidgets.QWidget):
    favoriteToggled = QtCore.Signal(str, str)
    groupToggled = QtCore.Signal(str, bool)
    copyRequested = QtCore.Signal(str)
    propertySelectionChanged = QtCore.Signal(str, bool)
    clearSelectionRequested = QtCore.Signal()
    copySelectionRequested = QtCore.Signal()

