        self._rows_by_selection_key: Dict[str, PropertyRow] = {}
        self._hovered_row: Optional[PropertyRow] = None
        self._selected_keys: Set[str] = set()
        self._selection_anchor_key = ""
        self._header_layout: Optional[QtWidgets.QGridLayout] = None
        self._property_col_width = 300
        self._value_col_width = PropertyRow.VALUE_COLUMN_MIN_WIDTH
        self._column_resize_active = False
        self._column_resize_start_global_x = 0
        self._column_resize_start_property_width = 0
        self._column_resize_handle_width = 10
