        header_layout.addWidget(self.property_header_label, 0, 1, 1, 1, QtCore.Qt.AlignVCenter | QtCore.Qt.AlignLeft)
        header_layout.addWidget(self.value_header_label, 0, 2, 1, 1, QtCore.Qt.AlignVCenter | QtCore.Qt.AlignLeft)
