    def _open_ifc_progress(self, label: str):
        self._close_ifc_progress()
        dlg = QtWidgets.QProgressDialog(label, "", 0, 0, self)
        dlg.setWindowTitle("IFC Import")
        dlg.setWindowModality(QtCore.Qt.WindowModal)
        dlg.setMinimumDuration(0)
        dlg.setCancelButton(None)
        dlg.setAutoClose(False)
        dlg.setAutoReset(False)
        dlg.show()
        self._ifc_progress_dialog = dlg
        QtWidgets.QApplication.processEvents()

    def _update_ifc_progress(self, label: str):
        if self._ifc_progress_dialog:
            self._ifc_progress_dialog.setLabelText(label)
            QtWidgets.QApplication.processEvents()

    def _close_ifc_progress(self):
        if self._ifc_progress_dialog:
            self._ifc_progress_dialog.close()
            self._ifc_progress_dialog.deleteLater()
            self._ifc_progress_dialog = None

    @staticmethod
    def _set_button_role(button: QtWidgets.QPushButton, role: str):
        button.setProperty("role", role)

    def _wrap_panel_in_scroll(self, panel: QtWidgets.QWidget, object_name: str) -> QtWidgets.QScrollArea:
        # Keep legacy panel wrappers parented to the main window so they can
        # never appear as accidental top-level windows.
        scroll = QtWidgets.QScrollArea(self)
        scroll.setObjectName(object_name)
        scroll.setWidgetResizable(True)
        scroll.setFrameShape(QtWidgets.QFrame.NoFrame)
        scroll.setHorizontalScrollBarPolicy(QtCore.Qt.ScrollBarAlwaysOff)
        scroll.setVerticalScrollBarPolicy(QtCore.Qt.ScrollBarAsNeeded)
        scroll.viewport().setAutoFillBackground(False)
        scroll.setWidget(panel)
        return scroll

