    def _workspace_panel_state_settings_key(self) -> str:
        return "workspace/panels_v2"

    def _load_workspace_panel_state(self) -> Dict[str, object]:
        merged_panels: Dict[str, Dict[str, object]] = {
            key: {"open": bool(value.get("open", True)), "dock": str(value.get("dock", "left"))}
            for key, value in dict(self._workspace_panel_defaults or {}).items()
        }
        payload: Dict[str, object] = {"panels": merged_panels, "splitterSizes": []}
        cached = dict(getattr(self.state, "ui_panel_layout_state", {}) or {})
        if cached:
            self._merge_workspace_panel_payload(payload, cached)
        try:
            settings = QtCore.QSettings("Ponker", "Resolve")
            raw = settings.value(self._workspace_panel_state_settings_key(), "")
            if isinstance(raw, dict):
                loaded = raw
            else:
                loaded = json.loads(str(raw or "{}"))
            if isinstance(loaded, dict):
                self._merge_workspace_panel_payload(payload, loaded)
        except Exception:
            pass
        return payload

    def _merge_workspace_panel_payload(self, target: Dict[str, object], source: Dict[str, object]) -> None:
        target_panels = dict(target.get("panels") or {})
        if "panels" in source and isinstance(source.get("panels"), dict):
            source_panels = dict(source.get("panels") or {})
        else:
            source_panels = dict(source or {})
        for panel_id, panel_state in source_panels.items():
            if panel_id not in target_panels or not isinstance(panel_state, dict):
                continue
            target_panels[panel_id]["open"] = bool(panel_state.get("open", target_panels[panel_id]["open"]))
            dock = str(panel_state.get("dock", target_panels[panel_id]["dock"])).lower().strip()
            if dock == "right":
                target_panels[panel_id]["dock"] = "right"
            elif dock in {"left_bottom", "left-bottom", "bottom_left", "leftbottom", "bottom"}:
                target_panels[panel_id]["dock"] = "left_bottom"
            else:
                target_panels[panel_id]["dock"] = "left"
        target["panels"] = target_panels
        raw_sizes = source.get("splitterSizes") if isinstance(source, dict) else None
        if isinstance(raw_sizes, list):
            normalized = [max(0, int(v)) for v in raw_sizes[:3]]
            if normalized:
                target["splitterSizes"] = normalized

    def _save_workspace_panel_state(self, state: Optional[Dict[str, object]] = None) -> None:
        raw_payload = dict(state or {})
        if "panels" in raw_payload:
            payload = {
                "panels": dict(raw_payload.get("panels") or {}),
                "splitterSizes": [max(0, int(v)) for v in list(raw_payload.get("splitterSizes") or [])[:3]],
            }
        else:
            payload = {"panels": dict(raw_payload), "splitterSizes": []}
        self.state.ui_panel_layout_state = dict(payload)
        try:
            settings = QtCore.QSettings("Ponker", "Resolve")
            settings.setValue(self._workspace_panel_state_settings_key(), json.dumps(payload, ensure_ascii=True))
        except Exception:
            pass

    def _on_workspace_panel_state_changed(self, state: Dict[str, object]) -> None:
        self._save_workspace_panel_state(state)

    def _toggle_workspace_panel(self, panel_id: str) -> None:
        if hasattr(self, "workspace_layout"):
            self.workspace_layout.toggle_panel(str(panel_id))

    def _bind_search_sets_panel_button(self) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        buttons = getattr(self.workspace_layout, "_panel_buttons", {})
        if not isinstance(buttons, dict):
            return
        button = buttons.get("searchSets")
        if button is None:
            return
        try:
            button.clicked.disconnect()
        except Exception:
            pass
        button.setCheckable(True)
        button.clicked.connect(self._on_search_sets_panel_button_clicked)

    def _on_search_sets_panel_button_clicked(self, checked: bool) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        if checked:
            self._activate_search_sets_workspace()
            return
        self.workspace_layout.set_panel_open("searchSets", False)

    def _activate_search_sets_workspace(self) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        self._open_search_sets_with_object_tree(focus_search_sets=True)

    def _set_search_workspace_side_by_side(self, enabled: bool) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        self.workspace_layout.set_left_side_by_side(
            bool(enabled),
            {
                "objectTree": "tree",
                "searchSets": "search",
                "findObjects": "find",
            },
        )

    def _on_workspace_left_dock_tab_changed(self, index: int) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        if index < 0:
            return
        current_widget = self.workspace_layout.left_dock.widget(index)
        if current_widget is self.search_sets_panel:
            self._open_search_sets_with_object_tree(focus_search_sets=False)

    def _on_workspace_left_search_dock_tab_changed(self, index: int) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        if index < 0:
            return
        current_widget = self.workspace_layout.left_search_dock.widget(index)
        if current_widget is self.search_sets_panel:
            self._open_search_sets_with_object_tree(focus_search_sets=False)

    def _open_search_sets_with_object_tree(self, *, focus_search_sets: bool) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        if self._search_set_workspace_syncing:
            return
        self._search_set_workspace_syncing = True
        try:
            self._set_search_workspace_side_by_side(True)
            self.workspace_layout.set_panel_dock("objectTree", "left")
            self.workspace_layout.set_panel_dock("searchSets", "left")
            self.workspace_layout.set_panel_dock("findObjects", "left")
            self.workspace_layout.set_panel_open("searchSets", True)
            self.workspace_layout.set_panel_open("objectTree", True)
            self.workspace_layout.set_panel_open("findObjects", True)
            if hasattr(self, "object_tree_panel"):
                self.object_tree_panel.show_by_file()
                self.object_tree_panel.show_tree_tab()
            self._center_workspace_for_search_sets()
            if focus_search_sets:
                self.workspace_layout.show_panel("searchSets")
        finally:
            self._search_set_workspace_syncing = False

    def _center_workspace_for_search_sets(self) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        splitter = getattr(self.workspace_layout, "splitter", None)
        right_wrap = getattr(self.workspace_layout, "right_dock_wrap", None)
        if splitter is None or right_wrap is None:
            return
        sizes = splitter.sizes()
        if len(sizes) != 3:
            return
        total = sum(max(0, int(v)) for v in sizes)
        if total <= 0:
            total = max(1280, int(self.width() or 1280))

        right_visible = bool(right_wrap.isVisible())
        side_by_side = bool(hasattr(self.workspace_layout, "left_side_by_side_enabled") and self.workspace_layout.left_side_by_side_enabled())
        left = max(460, int(total * 0.32)) if side_by_side else max(240, int(total * 0.22))
        right = max(240, int(total * 0.20)) if right_visible else 0
        center = total - left - right

        if center < 420:
            deficit = 420 - center
            if right_visible and right > 240:
                trim = min(deficit, right - 240)
                right -= trim
                deficit -= trim
            left_floor = 460 if side_by_side else 240
            if deficit > 0 and left > left_floor:
                trim = min(deficit, left - left_floor)
                left -= trim
                deficit -= trim
            center = total - left - right
        splitter.setSizes([left, max(420, center), right])

    def _workspace_panels_for_mode(self, mode: str) -> Dict[str, bool]:
        config = self.workspace_manager.config_for(mode)
        return {str(pid): bool(is_open) for pid, is_open in dict(config.panels or {}).items()}

    def _apply_workspace_mode_panels(self, mode: str) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        self._set_search_workspace_side_by_side(True)
        config = self.workspace_manager.config_for(mode)
        for panel_id, should_open in self._workspace_panels_for_mode(mode).items():
            self.workspace_layout.set_panel_open(panel_id, bool(should_open))
        self._apply_workspace_content(config)

    def _apply_workspace_content(self, config) -> None:
        if not hasattr(self, "workspace_layout"):
            return
        object_tree_view = str(getattr(config, "object_tree_view", "") or "").strip().lower()
        object_tree_tab = str(getattr(config, "object_tree_tab", "") or "").strip().lower()
        if hasattr(self, "object_tree_panel"):
            if object_tree_view == "ai":
                self.object_tree_panel.show_ai_views()
            elif object_tree_view == "by_file":
                self.object_tree_panel.show_by_file()
            if object_tree_tab in {"properties", "tree"}:
                self.object_tree_panel.show_tree_tab()
        clash_step = str(getattr(config, "clash_step", "") or "").strip().lower()
        if clash_step == "issues":
            clash_step = "fix" if self.state.selected_issue is not None else "results"
        if clash_step in {"setup", "results", "fix"} and hasattr(self, "_clash_workflow_state"):
            self._clash_workflow_state.activeStep = clash_step
            self._sync_clash_workflow_panel()
        focus_panel = str(getattr(config, "focus_panel", "") or "").strip()
        if focus_panel:
            self.workspace_layout.show_panel(focus_panel)

    def _is_model_workspace(self) -> bool:
        return self.workspace_manager.normalize(self._active_mode) == "Model"

    def _open_ai_panel_from_issue(self) -> None:
        if hasattr(self, "workspace_layout"):
            self.workspace_layout.show_panel("ai")
        if self.state.selected_issue is not None:
            self._clash_workflow_state.activeStep = "fix"
            self._sync_clash_workflow_panel()
        self._schedule_ai_card_refresh("open_ai_panel_from_issue")

    def _on_clash_workflow_step_changed(self, step: str) -> None:
        self._clash_workflow_state.activeStep = str(step or "setup")
        self._sync_clash_workflow_panel()

    def _on_clash_workflow_test_updated(self, updated_test: ClashTest) -> None:
        if not isinstance(updated_test, ClashTest):
            return
        self._active_clash_test = updated_test
        self._clash_workflow_state.selectedTestId = str(updated_test.id or "")
        try:
            self._clash_test_store.upsert_search_sets(self.state.search_sets)
            self._clash_test_store.save_test(updated_test, set_active=True)
        except Exception as exc:
            self.log(f"Failed to save clash test from workflow: {exc}")
        self._update_clash_test_settings_button()
        self._sync_clash_workflow_panel()

    def _run_clash_test_from_workflow(self) -> None:
        self._clash_workflow_state.activeStep = "setup"
        self._sync_clash_workflow_panel()
        self.generate_issues()

    def _show_clash_benchmark_tab(self, text: str) -> None:
        if not hasattr(self, "inspect_tabs"):
            return
        self.benchmark_log.setPlainText(str(text or ""))
        tab_index = self.inspect_tabs.indexOf(self.benchmark_tab)
        if tab_index < 0:
            tab_index = self.inspect_tabs.addTab(self.benchmark_tab, self._benchmark_tab_title)
        self.inspect_tabs.setCurrentIndex(tab_index)
        self.benchmark_log.verticalScrollBar().setValue(0)

    def _show_clash_benchmark_dialog(self, text: str) -> None:
        body_text = str(text or "")
        existing = getattr(self, "_clash_benchmark_dialog", None)
        if existing is not None:
            try:
                existing.close()
                existing.deleteLater()
            except Exception:
                pass
            self._clash_benchmark_dialog = None

        dialog = QtWidgets.QDialog(self)
        dialog.setWindowTitle("Clash Benchmark Log")
        dialog.resize(920, 640)
        layout = QtWidgets.QVBoxLayout(dialog)
        layout.setContentsMargins(10, 10, 10, 10)
        layout.setSpacing(8)

        toolbar = QtWidgets.QHBoxLayout()
        toolbar.setContentsMargins(0, 0, 0, 0)
        toolbar.setSpacing(6)
        save_btn = QtWidgets.QPushButton("Gem som tekst", dialog)
        close_btn = QtWidgets.QPushButton("Luk og glem", dialog)
        toolbar.addWidget(save_btn, 0)
        toolbar.addWidget(close_btn, 0)
        toolbar.addStretch(1)

        text_view = QtWidgets.QPlainTextEdit(dialog)
        text_view.setReadOnly(True)
        text_view.setLineWrapMode(QtWidgets.QPlainTextEdit.NoWrap)
        text_view.setPlainText(body_text)
        text_view.verticalScrollBar().setValue(0)

        layout.addLayout(toolbar, 0)
        layout.addWidget(text_view, 1)

        save_btn.clicked.connect(
            lambda _checked=False: self._save_clash_benchmark_text(str(text_view.toPlainText() or ""))
        )
        close_btn.clicked.connect(lambda _checked=False: self._forget_clash_benchmark())
        dialog.destroyed.connect(lambda _obj=None: setattr(self, "_clash_benchmark_dialog", None))

        self._clash_benchmark_dialog = dialog
        if self.isVisible():
            parent_geo = self.geometry()
            width = max(640, min(920, int(parent_geo.width() * 0.72)))
            height = max(420, min(640, int(parent_geo.height() * 0.72)))
            left = parent_geo.x() + max(0, (parent_geo.width() - width) // 2)
            top = parent_geo.y() + max(0, (parent_geo.height() - height) // 2)
            dialog.setGeometry(left, top, width, height)
        dialog.setWindowModality(QtCore.Qt.ApplicationModal)
        dialog.setModal(True)
        dialog.exec()

    def _save_clash_benchmark_text(self, text: str) -> None:
        content = str(text or "").strip()
        if not content:
            self.statusBar().showMessage("Ingen benchmark-log at gemme.", 2500)
            return
        default_name = f"clash_benchmark_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}.txt"
        path, _ = QtWidgets.QFileDialog.getSaveFileName(
            self,
            "Gem Clash Benchmark",
            default_name,
            "Text (*.txt);;All Files (*)",
        )
        if not path:
            return
        try:
            Path(path).write_text(content + "\n", encoding="utf-8")
            self.statusBar().showMessage(f"Benchmark log gemt: {Path(path).name}", 4000)
        except Exception as exc:
            self.statusBar().showMessage(f"Kunne ikke gemme benchmark-log: {exc}", 5000)

    def _save_clash_benchmark_log(self) -> None:
        self._save_clash_benchmark_text(str(self.benchmark_log.toPlainText() or ""))

    def _forget_clash_benchmark(self) -> None:
        if hasattr(self, "inspect_tabs"):
            tab_index = self.inspect_tabs.indexOf(self.benchmark_tab)
            if tab_index >= 0:
                self.inspect_tabs.removeTab(tab_index)
        self.benchmark_log.clear()
        dialog = getattr(self, "_clash_benchmark_dialog", None)
        self._clash_benchmark_dialog = None
        if dialog is not None:
            try:
                dialog.close()
                dialog.deleteLater()
            except Exception:
                pass
        self.statusBar().showMessage("Benchmark-log lukket og glemt.", 2500)

    def _close_clash_benchmark_tab(self) -> None:
        self._forget_clash_benchmark()

    def _run_clash_benchmark_from_menu(self) -> None:
        if bool(getattr(self, "_clash_benchmark_running", False)):
            self.statusBar().showMessage("Clash benchmark is already running.", 2500)
            return
        self._clash_benchmark_running = True
        self.statusBar().showMessage("Running ClashBench...", 2000)
        QtWidgets.QApplication.setOverrideCursor(QtCore.Qt.WaitCursor)
        QtWidgets.QApplication.processEvents()
        try:
            report = run_clash_benchmark(log=self.log)
            text = format_clash_benchmark(report)
            self._show_clash_benchmark_tab(text)
            self.log("")
            for line in str(text).splitlines():
                self.log(str(line))
            self.log("")
            self.statusBar().showMessage(
                f"Clash benchmark complete ({len(list(report.scenarios or []))} scenarios).",
                5000,
            )
            self._show_clash_benchmark_dialog(text)
        except Exception as exc:
            self.log(f"Clash benchmark failed: {exc}")
            self.log(traceback.format_exc())
            self.statusBar().showMessage(f"Clash benchmark failed: {exc}", 5000)
            QtWidgets.QMessageBox.critical(
                self,
                "Clash Benchmark Fejl",
                f"Benchmark kunne ikke køres:\n{exc}",
            )
        finally:
            QtWidgets.QApplication.restoreOverrideCursor()
            self._clash_benchmark_running = False

    def _review_clashes_from_workflow(self) -> None:
        if not self._move_issue_selection(1):
            self.statusBar().showMessage("No clashes to review.", 2500)
            return
        self._clash_workflow_state.activeStep = "fix"
        self._sync_clash_workflow_panel()

    def _review_issue_rows(self) -> List[int]:
        return [idx for idx, issue in enumerate(list(self._issue_row_items or [])) if issue is not None]

    def _move_issue_selection(self, delta: int) -> bool:
        rows = self._review_issue_rows()
        if not rows:
            return False
        step = 1 if int(delta or 0) >= 0 else -1
        current = int(self.issues_list.currentRow())
        target = rows[0] if step > 0 else rows[-1]
        if current in rows:
            pos = rows.index(current)
            target = rows[(pos + step) % len(rows)]
        self.issues_list.setCurrentRow(int(target))
        return True

    def _is_text_entry_focus(self) -> bool:
        widget = QtWidgets.QApplication.focusWidget()
        return isinstance(
            widget,
            (
                QtWidgets.QLineEdit,
                QtWidgets.QTextEdit,
                QtWidgets.QPlainTextEdit,
                QtWidgets.QComboBox,
                QtWidgets.QAbstractSpinBox,
            ),
        )

    def _can_use_clash_review_shortcuts(self) -> bool:
        if self._issues_view_mode != "per_issue":
            return False
        if self._is_text_entry_focus():
            return False
        return bool(self._review_issue_rows())

    def _frame_selection_shortcut(self) -> None:
        if self._is_text_entry_focus():
            return
        self._focus_selected_issue()

    def _next_clash_shortcut(self) -> None:
        if not self._can_use_clash_review_shortcuts():
            return
        self._move_issue_selection(1)

    def _previous_clash_shortcut(self) -> None:
        if not self._can_use_clash_review_shortcuts():
            return
        self._move_issue_selection(-1)

    def _resolve_clash_shortcut(self) -> None:
        if not self._can_use_clash_review_shortcuts():
            return
        if self.state.selected_issue is None:
            self._move_issue_selection(1)
        if self._mark_current_clash_resolved(move_to_next=True, announce=False):
            self.statusBar().showMessage("Resolved. Next clash selected.", 2000)

    def _ignore_clash_shortcut(self) -> None:
        if not self._can_use_clash_review_shortcuts():
            return
        if self.state.selected_issue is None:
            self._move_issue_selection(1)
        if self._mark_current_clash_closed(move_to_next=True, announce=False):
            self.statusBar().showMessage("Ignored. Next clash selected.", 2000)

    def _apply_suggested_fix_from_workflow(self) -> None:
        if self._recommended_fix is None:
            self.generate_fixes()
            return
        self._preview_recommended_fix()
        self.statusBar().showMessage("Suggested fix preview applied.", 3000)
        self._sync_clash_workflow_panel()

    def _go_to_selected_clash(self) -> None:
        issue = self.state.selected_issue
        if issue is None:
            self.statusBar().showMessage("Select a clash first.", 2500)
            return
        focused = self._go_to_clash(issue)
        if focused:
            self.statusBar().showMessage("Moved to selected clash.", 2500)
        else:
            self.statusBar().showMessage("Could not frame selected clash.", 2500)

    def _show_fix_alternatives_from_workflow(self) -> None:
        if hasattr(self, "alternatives_toggle"):
            self.alternatives_toggle.setChecked(True)
        self.statusBar().showMessage("Alternatives opened.", 2000)

    def _issue_tracker_key(self, issue: Optional[Issue]) -> str:
        if issue is None:
            return ""
        key = str(issue.issue_id or "").strip()
        if key:
            return key
        diag = dict(issue.clash_diagnostics or {})
        result_diag = dict(diag.get("result") or {})
        return str(result_diag.get("clashKey") or "").strip()

    def _issue_tracker_test_id(self, issue: Optional[Issue]) -> str:
        if issue is None:
            return ""
        diag = dict(issue.clash_diagnostics or {})
        test_diag = dict(diag.get("test") or {})
        test_id = str(test_diag.get("id") or "").strip()
        if test_id:
            return test_id
        if self._active_clash_test is not None:
            return str(getattr(self._active_clash_test, "id", "") or "").strip()
        return ""

    def _apply_issue_tracker_meta(self, issue: Issue, meta: Dict[str, Any]) -> None:
        if issue is None or not isinstance(meta, dict):
            return
        key = str(meta.get("clashKey") or self._issue_tracker_key(issue) or "").strip()
        if key:
            issue.issue_id = key
        diagnostics = dict(issue.clash_diagnostics or {})
        result_diag = dict(diagnostics.get("result") or {})
        result_diag.update(
            {
                "clashKey": key or result_diag.get("clashKey"),
                "kind": "clash",
                "status": str(meta.get("status") or result_diag.get("status") or "new"),
                "reopened": bool(meta.get("reopened") or False),
                "reopenCount": int(meta.get("reopenCount") or 0),
                "firstSeenAt": float(meta.get("firstSeenAt")) if meta.get("firstSeenAt") is not None else result_diag.get("firstSeenAt"),
                "lastSeenAt": float(meta.get("lastSeenAt")) if meta.get("lastSeenAt") is not None else result_diag.get("lastSeenAt"),
                "updatedAt": float(meta.get("updatedAt")) if meta.get("updatedAt") is not None else result_diag.get("updatedAt"),
            }
        )
        diagnostics["result"] = result_diag
        lifecycle = dict(diagnostics.get("lifecycle") or {})
        lifecycle.update(
            {
                "clashKey": key or lifecycle.get("clashKey"),
                "reopened": bool(meta.get("reopened") or False),
                "reopenCount": int(meta.get("reopenCount") or lifecycle.get("reopenCount") or 0),
                "firstSeenAt": float(meta.get("firstSeenAt")) if meta.get("firstSeenAt") is not None else lifecycle.get("firstSeenAt"),
                "lastSeenAt": float(meta.get("lastSeenAt")) if meta.get("lastSeenAt") is not None else lifecycle.get("lastSeenAt"),
                "updatedAt": float(meta.get("updatedAt")) if meta.get("updatedAt") is not None else lifecycle.get("updatedAt"),
            }
        )
        diagnostics["lifecycle"] = lifecycle
        if isinstance(meta.get("comments"), list):
            diagnostics["comments"] = list(meta.get("comments") or [])
        issue.clash_diagnostics = diagnostics

    def _set_current_issue_tracker_status(self, status: str) -> bool:
        issue = self.state.selected_issue
        return self._set_issue_tracker_status_for_issue(issue, status)

    def _set_issue_tracker_status_for_issue(self, issue: Optional[Issue], status: str) -> bool:
        if issue is None:
            return False
        test_id = self._issue_tracker_test_id(issue)
        clash_key = self._issue_tracker_key(issue)
        if not test_id or not clash_key:
            return False
        try:
            meta = self._clash_test_store.update_result_status(
                test_id=test_id,
                clash_key=clash_key,
                status=str(status or "").strip().lower(),
            )
        except Exception as exc:
            self.log(f"Issue tracker status update failed: {exc}")
            return False
        if not meta:
            return False
        self._apply_issue_tracker_meta(issue, meta)
        lookup_key = f"{test_id}::{clash_key}"
        self._clash_run_cache.issue_lookup[lookup_key] = dict(meta or {})
        return True

    def _mark_current_clash_resolved(self, *, move_to_next: bool = False, announce: bool = True) -> bool:
        issue = self.state.selected_issue
        if issue is None:
            if announce:
                self.statusBar().showMessage("Select a clash first.", 2500)
            return False
        if self._set_current_issue_tracker_status("resolved"):
            issue.fix_status = "OK"
            clash_key = self._issue_tracker_key(issue)
            self._refresh_issue_list()
            if clash_key:
                self._select_issue_by_key(clash_key)
            if move_to_next:
                self._move_issue_selection(1)
            if announce:
                self.statusBar().showMessage("Issue marked as resolved.", 2500)
            return True
        if announce:
            self.statusBar().showMessage("Could not mark issue as resolved.", 3000)
        return False

    def _mark_current_clash_closed(self, *, move_to_next: bool = False, announce: bool = True) -> bool:
        issue = self.state.selected_issue
        if issue is None:
            if announce:
                self.statusBar().showMessage("Select a clash first.", 2500)
            return False
        if self._set_current_issue_tracker_status("closed"):
            issue.fix_status = "NoSolution"
            clash_key = self._issue_tracker_key(issue)
            self._refresh_issue_list()
            if clash_key:
                self._select_issue_by_key(clash_key)
            if move_to_next:
                self._move_issue_selection(1)
            if announce:
                self.statusBar().showMessage("Issue marked as closed.", 2500)
            return True
        if announce:
            self.statusBar().showMessage("Could not mark issue as closed.", 3000)
        return False

    def _mark_current_clash_approved(self) -> None:
        self._mark_current_clash_resolved()

    def _issue_group_id(self, issue: Optional[Issue]) -> str:
        if issue is None:
            return ""
        group_id = str(issue.group_id or "").strip()
        if group_id:
            return group_id
        group_diag = dict((issue.clash_diagnostics or {}).get("group") or {})
        return str(group_diag.get("id") or group_diag.get("groupId") or "").strip()

    def _issues_in_same_group(self, issue: Optional[Issue]) -> List[Issue]:
        if issue is None:
            return []
        group_id = self._issue_group_id(issue)
        if not group_id:
            return [issue]
        out: List[Issue] = []
        for candidate in list(self.state.bcf_issues or []):
            if self._issue_group_id(candidate) == group_id:
                out.append(candidate)
        return out or [issue]

    def _select_issue_by_key(self, clash_key: str) -> bool:
        wanted = str(clash_key or "").strip()
        if not wanted:
            return False
        for idx, issue in enumerate(list(self._issue_row_items or [])):
            if issue is None:
                continue
            if self._issue_tracker_key(issue) == wanted:
                self.issues_list.setCurrentRow(int(idx))
                return True
        return False

    def _set_status_for_issues(self, issues: List[Issue], status: str) -> int:
        changed = 0
        for issue in list(issues or []):
            if self._set_issue_tracker_status_for_issue(issue, status):
                if str(status).strip().lower() == "resolved":
                    issue.fix_status = "OK"
                elif str(status).strip().lower() == "closed":
                    issue.fix_status = "NoSolution"
                changed += 1
        return int(changed)

    def _mark_current_group_resolved(self) -> None:
        issue = self.state.selected_issue
        if issue is None:
            self.statusBar().showMessage("Select a clash first.", 2500)
            return
        targets = self._issues_in_same_group(issue)
        selected_key = self._issue_tracker_key(issue)
        changed = self._set_status_for_issues(targets, "resolved")
        if changed <= 0:
            self.statusBar().showMessage("Could not resolve group.", 3000)
            return
        self._refresh_issue_list()
        if selected_key:
            self._select_issue_by_key(selected_key)
        self.statusBar().showMessage(f"Resolved {changed} clashes in group.", 3000)

    def _mark_current_group_closed(self) -> None:
        issue = self.state.selected_issue
        if issue is None:
            self.statusBar().showMessage("Select a clash first.", 2500)
            return
        targets = self._issues_in_same_group(issue)
        selected_key = self._issue_tracker_key(issue)
        changed = self._set_status_for_issues(targets, "closed")
        if changed <= 0:
            self.statusBar().showMessage("Could not ignore group.", 3000)
            return
        self._refresh_issue_list()
        if selected_key:
            self._select_issue_by_key(selected_key)
        self.statusBar().showMessage(f"Ignored {changed} clashes in group.", 3000)

    def _save_issue_comment(self) -> None:
        issue = self.state.selected_issue
        if issue is None:
            self.statusBar().showMessage("Select an issue first.", 2500)
            return
        text = str(self.issue_comment_edit.text() or "").strip()
        if not text:
            self.statusBar().showMessage("Write a comment first.", 2500)
            return
        test_id = self._issue_tracker_test_id(issue)
        clash_key = self._issue_tracker_key(issue)
        if not test_id or not clash_key:
            self.statusBar().showMessage("Issue key missing. Run clash test again.", 3000)
            return
        try:
            meta = self._clash_test_store.append_result_comment(
                test_id=test_id,
                clash_key=clash_key,
                comment=text,
            )
        except Exception as exc:
            self.log(f"Issue tracker comment save failed: {exc}")
            self.statusBar().showMessage("Could not save comment.", 3000)
            return
        if not meta:
            self.statusBar().showMessage("Could not save comment.", 3000)
            return
        self.issue_comment_edit.clear()
        self._apply_issue_tracker_meta(issue, meta)
        lookup_key = f"{test_id}::{clash_key}"
        self._clash_run_cache.issue_lookup[lookup_key] = dict(meta or {})
        self._update_issue_details_panel(issue)
        self._refresh_issue_list()
        self.statusBar().showMessage("Comment saved.", 2000)

    def _assign_current_clash(self) -> None:
        issue = self.state.selected_issue
        if issue is None:
            self.statusBar().showMessage("Select a clash first.", 2500)
            return
        value, ok = QtWidgets.QInputDialog.getText(self, "Assign clash", "Assignee")
        if not ok:
            return
        assignee = str(value or "").strip()
        if assignee:
            issue.assignee = assignee
            self.statusBar().showMessage(f"Assigned to {assignee}.", 2500)
        else:
            issue.assignee = None
            self.statusBar().showMessage("Assignment cleared.", 2500)
        self._refresh_issue_list()

    def _sync_clash_workflow_panel(self) -> None:
        if not hasattr(self, "clash_detection_panel"):
            return
        search_sets = [(str(s.id), str(s.name)) for s in list(self.state.search_sets or []) if getattr(s, "id", None)]
        if self._active_clash_test is not None and not self._clash_workflow_state.selectedTestId:
            self._clash_workflow_state.selectedTestId = str(self._active_clash_test.id or "")
        self.clash_detection_panel.set_model_loaded(bool(self.state.ifc_model))
        self.clash_detection_panel.set_available_search_sets(search_sets)
        self.clash_detection_panel.set_active_test(self._active_clash_test)
        self.clash_detection_panel.set_clash_selected(bool(self.state.selected_issue))
        self.clash_detection_panel.set_has_suggested_fix(self._recommended_fix is not None)
        summary = "Select a clash in Results."
        if self._recommended_fix is not None:
            summary = "Suggested fix ready."
        if hasattr(self, "viewer_clash_card_summary") and self.viewer_clash_card_summary.text():
            summary = str(self.viewer_clash_card_summary.text())
        self.clash_detection_panel.set_ai_summary(summary)
        self.clash_detection_panel.set_workflow_state(self._clash_workflow_state)

    def _make_card_splitter(self, object_name: str, cards: List[QtWidgets.QWidget]) -> QtWidgets.QSplitter:
        splitter = QtWidgets.QSplitter(QtCore.Qt.Vertical)
        splitter.setObjectName(object_name)
        splitter.setChildrenCollapsible(False)
        splitter.setHandleWidth(9)
        for card in list(cards or []):
            card.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Expanding)
            card.setMinimumHeight(max(110, int(card.minimumHeight() or 0)))
            card.setToolTip("Right-click card: move up/down or resize. Drag splitter handles to resize.")
            card.setContextMenuPolicy(QtCore.Qt.CustomContextMenu)
            card.customContextMenuRequested.connect(
                lambda pos, target=card, owner=splitter: self._open_card_context_menu(owner, target, pos)
            )
            splitter.addWidget(card)
        if splitter.count() > 0:
            splitter.setStretchFactor(splitter.count() - 1, 1)
        return splitter

    def _open_card_context_menu(
        self,
        splitter: QtWidgets.QSplitter,
        card: QtWidgets.QWidget,
        pos: QtCore.QPoint,
    ) -> None:
        idx = splitter.indexOf(card)
        if idx < 0:
            return
        menu = QtWidgets.QMenu(self)
        move_up = menu.addAction("Move up")
        move_down = menu.addAction("Move down")
        menu.addSeparator()
        grow = menu.addAction("Increase height")
        shrink = menu.addAction("Decrease height")
        menu.addSeparator()
        reset = menu.addAction("Equalize card heights")
        move_up.setEnabled(idx > 0)
        move_down.setEnabled(idx < (splitter.count() - 1))
        action = menu.exec(card.mapToGlobal(pos))
        if action is move_up:
            self._move_card_in_splitter(splitter, card, -1)
        elif action is move_down:
            self._move_card_in_splitter(splitter, card, 1)
        elif action is grow:
            self._resize_card_in_splitter(splitter, card, +60)
        elif action is shrink:
            self._resize_card_in_splitter(splitter, card, -60)
        elif action is reset:
            count = splitter.count()
            if count > 0:
                splitter.setSizes([1] * count)

    def _move_card_in_splitter(
        self,
        splitter: QtWidgets.QSplitter,
        card: QtWidgets.QWidget,
        direction: int,
    ) -> None:
        idx = splitter.indexOf(card)
        if idx < 0:
            return
        target = idx + int(direction)
        if target < 0 or target >= splitter.count():
            return
        sizes = list(splitter.sizes())
        splitter.insertWidget(target, card)
        if sizes:
            splitter.setSizes(sizes)

    def _resize_card_in_splitter(
        self,
        splitter: QtWidgets.QSplitter,
        card: QtWidgets.QWidget,
        delta_px: int,
    ) -> None:
        idx = splitter.indexOf(card)
        if idx < 0:
            return
        sizes = list(splitter.sizes())
        if idx >= len(sizes):
            return
        total = sum(max(1, int(v)) for v in sizes)
        if total <= 0:
            return
        delta = int(delta_px)
        new_size = max(90, int(sizes[idx]) + delta)
        applied = new_size - int(sizes[idx])
        if applied == 0:
            return
        sizes[idx] = new_size
        spread_indices = [i for i in range(len(sizes)) if i != idx and sizes[i] > 90]
        if spread_indices:
            share = int(applied / max(1, len(spread_indices)))
            rem = applied
            for sidx in spread_indices:
                cut = share
                if rem != 0:
                    cut = int(rem / max(1, len(spread_indices)))
                candidate = max(90, int(sizes[sidx]) - cut)
                diff = int(sizes[sidx]) - candidate
                sizes[sidx] = candidate
                rem -= diff
        splitter.setSizes(sizes)

    def _apply_card_shadow(self, widget: QtWidgets.QWidget):
        effect = QtWidgets.QGraphicsDropShadowEffect(self)
        effect.setBlurRadius(28)
        effect.setOffset(0, 8)
        effect.setColor(QColor(0, 0, 0, 78))
        widget.setGraphicsEffect(effect)

    def _apply_decision_card_glow(self):
        ar, ag, ab = hex_to_rgb(self.COLOR_ACCENT)
        self._decision_glow_effect = QtWidgets.QGraphicsDropShadowEffect(self)
        self._decision_glow_effect.setBlurRadius(28)
        self._decision_glow_effect.setOffset(0, 0)
        self._decision_glow_effect.setColor(QColor(ar, ag, ab, self._decision_glow_alpha))
        self.decision_shell.setGraphicsEffect(self._decision_glow_effect)
        self._set_decision_visual_state(False, animate=False)

    def _apply_generate_button_glow(self):
        ar, ag, ab = hex_to_rgb(self.COLOR_ACCENT)
        self._generate_button_effect = QtWidgets.QGraphicsDropShadowEffect(self)
        self._generate_button_effect.setBlurRadius(22)
        self._generate_button_effect.setOffset(0, 1)
        self._generate_button_effect.setColor(QColor(ar, ag, ab, 72))
        self.gen_fixes_btn.setGraphicsEffect(self._generate_button_effect)

    def _set_decision_glow_alpha(self, alpha: int):
        self._decision_glow_alpha = int(float(alpha))
        if self._decision_glow_effect:
            ar, ag, ab = hex_to_rgb(self.COLOR_ACCENT)
            self._decision_glow_effect.setColor(QColor(ar, ag, ab, self._decision_glow_alpha))

    def _stop_decision_glow_pulse(self):
        if self._decision_glow_pulse:
            self._decision_glow_pulse.stop()
            self._decision_glow_pulse = None

    def _start_decision_glow_pulse(self, base_alpha: int):
        if not self._decision_glow_effect:
            return
        self._stop_decision_glow_pulse()
        base = max(22, int(base_alpha))
        peak = min(110, base + 18)
        self._decision_glow_pulse = QtCore.QVariantAnimation(self)
        self._decision_glow_pulse.setDuration(2300)
        self._decision_glow_pulse.setLoopCount(-1)
        self._decision_glow_pulse.setEasingCurve(QtCore.QEasingCurve.InOutSine)
        self._decision_glow_pulse.setStartValue(base)
        self._decision_glow_pulse.setKeyValueAt(0.5, peak)
        self._decision_glow_pulse.setEndValue(base)
        self._decision_glow_pulse.valueChanged.connect(
            lambda value: self._set_decision_glow_alpha(int(float(value)))
        )
        self._decision_glow_pulse.start()

    def _pulse_decision_glow_once(self):
        if not self._decision_glow_effect:
            return
        if self._decision_has_results:
            self._start_decision_glow_pulse(max(70, self._decision_glow_alpha))
            return
        self._stop_decision_glow_pulse()
        if self._decision_glow_animation:
            self._decision_glow_animation.stop()
        base = max(22, self._decision_glow_alpha)
        peak = min(90, base + 24)
        self._decision_glow_animation = QtCore.QVariantAnimation(self)
        self._decision_glow_animation.setDuration(1700)
        self._decision_glow_animation.setEasingCurve(QtCore.QEasingCurve.InOutSine)
        self._decision_glow_animation.setStartValue(base)
        self._decision_glow_animation.setKeyValueAt(0.5, peak)
        self._decision_glow_animation.setEndValue(base)
        self._decision_glow_animation.valueChanged.connect(
            lambda value: self._set_decision_glow_alpha(int(float(value)))
        )
        self._decision_glow_animation.start()

    def _set_decision_visual_state(self, has_results: bool, animate: bool = True):
        self._decision_has_results = bool(has_results)
        self.decision_shell.setProperty("aiActive", self._decision_has_results)
        self.decision_group.setProperty("aiActive", self._decision_has_results)
        self.decision_shell.style().unpolish(self.decision_shell)
        self.decision_shell.style().polish(self.decision_shell)
        self.decision_group.style().unpolish(self.decision_group)
        self.decision_group.style().polish(self.decision_group)

        if not self._decision_glow_effect:
            return
        target_alpha = 70 if self._decision_has_results else 22
        if not self._decision_has_results:
            self._stop_decision_glow_pulse()
        if self._decision_glow_animation:
            self._decision_glow_animation.stop()
        if not animate:
            self._set_decision_glow_alpha(target_alpha)
            if self._decision_has_results:
                self._start_decision_glow_pulse(target_alpha)
            return
        self._decision_glow_animation = QtCore.QVariantAnimation(self)
        self._decision_glow_animation.setDuration(520)
        self._decision_glow_animation.setEasingCurve(QtCore.QEasingCurve.InOutCubic)
        self._decision_glow_animation.setStartValue(self._decision_glow_alpha)
        self._decision_glow_animation.setEndValue(target_alpha)
        self._decision_glow_animation.valueChanged.connect(
            lambda value: self._set_decision_glow_alpha(int(float(value)))
        )
        if self._decision_has_results:
            self._decision_glow_animation.finished.connect(
                lambda: self._start_decision_glow_pulse(target_alpha)
            )
        self._decision_glow_animation.start()

    def _pulse_generate_button(self):
        if not self._generate_button_effect:
            return
        if self._generate_button_pulse:
            self._generate_button_pulse.stop()
        self._generate_button_pulse = QtCore.QVariantAnimation(self)
        self._generate_button_pulse.setDuration(560)
        self._generate_button_pulse.setEasingCurve(QtCore.QEasingCurve.InOutCubic)
        self._generate_button_pulse.setStartValue(0.0)
        self._generate_button_pulse.setEndValue(1.0)

        def _on_pulse(value):
            wave = math.sin(float(value) * math.pi)
            alpha = int(72 + 52 * wave)
            blur = 22 + 7 * wave
            if self._generate_button_effect:
                self._generate_button_effect.setBlurRadius(blur)
                hr, hg, hb = hex_to_rgb(self.COLOR_ACCENT_HOVER)
                self._generate_button_effect.setColor(QColor(hr, hg, hb, alpha))

        def _reset_pulse():
            if self._generate_button_effect:
                self._generate_button_effect.setBlurRadius(22)
                ar, ag, ab = hex_to_rgb(self.COLOR_ACCENT)
                self._generate_button_effect.setColor(QColor(ar, ag, ab, 72))

        self._generate_button_pulse.valueChanged.connect(_on_pulse)
        self._generate_button_pulse.finished.connect(_reset_pulse)
        self._generate_button_pulse.start()

    def _animate_clearance_value(self, clearance_mm: float):
        if self._clearance_animation:
            self._clearance_animation.stop()
        sign = "+" if clearance_mm >= 0 else "-"
        target_abs = abs(float(clearance_mm))
        self._clearance_animation = QtCore.QVariantAnimation(self)
        self._clearance_animation.setDuration(420)
        self._clearance_animation.setEasingCurve(QtCore.QEasingCurve.InOutCubic)
        self._clearance_animation.setStartValue(0.0)
        self._clearance_animation.setEndValue(target_abs)
        self._clearance_animation.valueChanged.connect(
            lambda value: self.effect_clearance.setText(f"{sign}{float(value):.0f} mm")
        )
        self._clearance_animation.finished.connect(
            lambda: self.effect_clearance.setText(f"{sign}{target_abs:.0f} mm")
        )
        self._clearance_animation.start()

    def _status_dot_icon(self, color_hex: str) -> QIcon:
        key = str(color_hex or "").lower()
        cached = self._status_dot_icons.get(key)
        if cached:
            return cached
        pixmap = QPixmap(12, 12)
        pixmap.fill(QtCore.Qt.transparent)
        painter = QPainter(pixmap)
        painter.setRenderHint(QPainter.Antialiasing, True)
        painter.setPen(QtCore.Qt.NoPen)
        painter.setBrush(QColor(color_hex))
        painter.drawEllipse(2, 2, 8, 8)
        painter.end()
        icon = QIcon(pixmap)
        self._status_dot_icons[key] = icon
        return icon

