        self._properties_group_items.clear()
        self._properties_group_nodes.clear()
        self._properties_current_group = None
        self._properties_group_labels.clear()
        self._properties_table_sources = []
        self._properties_flat_rows_cache = []
        self.properties_summary_name.setText("-")
        self.properties_summary_guid.setText("-")
        self.properties_summary_type.setText("-")
        self.properties_summary_system.setText("-")
        self.properties_summary_discipline.setText("-")
        self.properties_summary_class.setText("-")
        self.properties_summary_file.setText("-")
        self.properties_summary_counts.setText("-")
        self.properties_tree.clear()
        item = QtWidgets.QTreeWidgetItem([message])
        self.properties_tree.addTopLevelItem(item)
        self.properties_table.setRowCount(1)
        self.properties_table.setItem(0, 0, QtWidgets.QTableWidgetItem(" "))
        self.properties_table.setItem(0, 1, QtWidgets.QTableWidgetItem(message))
        self.properties_table.setItem(0, 2, QtWidgets.QTableWidgetItem(""))
        self.properties_table.setItem(0, 3, QtWidgets.QTableWidgetItem(""))
